typedef enum SDL_EventAction
{
 SDL_ADDEVENT, /**< تشير هذه القيمة إلى أن SDL يضيف الأحداث الجديدة إلى نهاية الطابور عند تنفيذ هذا الطلب. */
 SDL_PEEKEVENT, /**< تشير هذه القيمة إلى أن SDL يفحص مقدمة الطابور دون إزالة الأحداث منه أثناء هذا الطلب. */
 SDL_GETEVENT /**< تشير هذه القيمة إلى أن SDL يسحب الأحداث من مقدمة الطابور ويزيلها أثناء هذا الطلب. */
} SDL_EventAction;
